script:
function setupForm({ doc, call, toast, $dialog }) {
    // Hide default Assign To button + avatar indicators for non-managers
    call("aionion_custom.aionion_custom.controllers.crm_lead.get_current_user_roles", {})
    .then(function(roles) {
        var managerRoles = ["Insurance Sales Manager","Insurance Renewals Manager",
            "US Subscription Admin","Capital Manager","Global RM Manager","System Manager","Administrator"];
        var isManager = roles.some(function(r) { return managerRoles.indexOf(r) !== -1; });
        if (isManager) {
            document.body.classList.add("aion-manager");
        } else {
            document.body.classList.remove("aion-manager");
        }
    });

    const actions = []

    // ── FIELD VISIBILITY (CSS-class approach — persists through Vue re-renders) ──
    const FIELD_CLASS_MAP = {
        "Parent Policy": "aion-f-parent-policy",
        "Parent Policy Expiry Date": "aion-f-parent-expiry",
        "Insurance Company (Renewal)": "aion-f-renewal-company",
        "Source Lead": "aion-f-source-lead",
        "Renewal Due Date": "aion-f-renewal-due",
        "Status": "aion-f-status",
        "Remarks": "aion-f-remarks",
        "Upsell": "aion-f-upsell",
        "Upsell Remarks": "aion-f-upsell-remarks",
        "Sum Insured Current Year": "aion-f-sum-insured-cy",
        "Updated Insurance Company Name": "aion-f-updated-ins-co",
        "Plan Name": "aion-f-plan-name",
        "Updated Policy Number": "aion-f-updated-pol-no",
        "Updated Sum Insured": "aion-f-updated-sum",
        "Payment Mode": "aion-f-payment-mode",
        "Occupation": "aion-f-occupation",
        "ITR Filed": "aion-f-itr",
        "Annual Income": "aion-f-annual-income",
        "Education Qualification": "aion-f-education",
        "Smoker Status": "aion-f-smoker",
        "Height": "aion-f-height",
        "Weight (kg)": "aion-f-weight",
        "Vehicle Year": "aion-f-vehicle-year",
        "Vehicle Type": "aion-f-vehicle-type",
        "Policy Copy / RC Book": "aion-f-policy-copy",
        "Vehicle Number": "aion-f-vehicle-no",
        "Vehicle Make and Model": "aion-f-vehicle-make",
        "Country of Travel": "aion-f-travel-country",
        "Duration of Travel (days)": "aion-f-travel-duration",
        "Coverage Amount (USD)": "aion-f-travel-coverage",
        "Health Type": "aion-f-health-type",
        "Pre-Existing Disease (PED)": "aion-f-ped",
        "PED Description": "aion-f-ped-desc",
    }

    const RENEWAL_FIELDS = [
        "aion-f-parent-policy","aion-f-parent-expiry","aion-f-renewal-company",
        "aion-f-source-lead","aion-f-renewal-due","aion-f-status","aion-f-remarks",
        "aion-f-upsell","aion-f-upsell-remarks","aion-f-sum-insured-cy",
        "aion-f-updated-ins-co","aion-f-plan-name","aion-f-updated-pol-no","aion-f-updated-sum"
    ]
    const TERM_FIELDS = [
        "aion-f-payment-mode","aion-f-occupation","aion-f-itr","aion-f-annual-income",
        "aion-f-education","aion-f-smoker","aion-f-height","aion-f-weight"
    ]
    const MOTOR_FIELDS = [
        "aion-f-vehicle-year","aion-f-vehicle-type","aion-f-policy-copy",
        "aion-f-vehicle-no","aion-f-vehicle-make"
    ]
    const TRAVEL_FIELDS = ["aion-f-travel-country","aion-f-travel-duration","aion-f-travel-coverage"]
    const HEALTH_FIELDS = ["aion-f-health-type","aion-f-ped","aion-f-ped-desc"]

    const tagFields = () => {
        const walk = (node) => {
            if (node.nodeType === 3) {
                const t = node.textContent.trim()
                const cls = FIELD_CLASS_MAP[t]
                if (cls) {
                    const field = node.parentElement?.closest(".field")
                    if (field && !field.classList.contains(cls)) field.classList.add(cls)
                }
            }
            node.childNodes.forEach(walk)
        }
        walk(document.body)
    }

    const updateCSS = () => {
        const entity   = doc.custom_entity
        const product  = doc.custom_product
        const insType  = doc.custom_insurance_type
        const isIns    = entity === "Aionion Insurance"
        const isRenewal = product === "Insurance Renewals"

        let style = document.getElementById("aion-vis")
        if (!style) {
            style = document.createElement("style")
            style.id = "aion-vis"
            document.head.appendChild(style)
        }

        const hide = (classes) => classes.map(c => `.${c}{display:none!important}`).join("")
        let css = ""

        if (!isIns) {
            css += hide([...RENEWAL_FIELDS,...TERM_FIELDS,...MOTOR_FIELDS,...TRAVEL_FIELDS,...HEALTH_FIELDS])
        } else if (isRenewal) {
            if (insType !== "Health") css += hide(HEALTH_FIELDS)
            if (insType !== "Term")   css += hide(TERM_FIELDS)
            if (insType !== "Motor")  css += hide(MOTOR_FIELDS)
            if (insType !== "Travel") css += hide(TRAVEL_FIELDS)
        } else {
            css += hide(RENEWAL_FIELDS)
            if (insType !== "Health") css += hide(HEALTH_FIELDS)
            if (insType !== "Term")   css += hide(TERM_FIELDS)
            if (insType !== "Motor")  css += hide(MOTOR_FIELDS)
            if (insType !== "Travel") css += hide(TRAVEL_FIELDS)
        }

        style.textContent = css
    }

    const applyVisibility = () => { tagFields(); updateCSS() }

    // Run multiple times to catch lazy-rendered fields
    setTimeout(applyVisibility, 200)
    setTimeout(applyVisibility, 600)
    setTimeout(applyVisibility, 1200)
    setTimeout(applyVisibility, 2500)
    if (window._aion_iv) clearInterval(window._aion_iv)
    window._aion_iv = setInterval(applyVisibility, 1000)
    setTimeout(() => clearInterval(window._aion_iv), 20000)

        // ── INSURANCE ────────────────────────────────────────────
    if (doc.custom_entity === "Aionion Insurance") {



        if ((!doc.docstatus || doc.docstatus === 0) && !doc.custom_service_rm) {
            actions.push({
                label: "Assign Service RM",
                onClick: () => {
                    // Try manager flow first
                    call("aionion_custom.aionion_custom.controllers.crm_lead.get_rm_list_for_manager",
                        { lead_name: doc.name }
                    ).then((res) => {
                        if (res.is_manager) {
                            // Manager: show full RM list — can reassign anytime
                            $dialog({
                                title: "Assign Service RM",
                                message: "Select RM to assign:",
                                actions: res.rm_list.map(rm => ({
                                    label: rm.employee_name + " — " + rm.lead_count + " active leads",
                                    variant: "outline",
                                    onClick: (close) => {
                                        call("aionion_custom.aionion_custom.controllers.crm_lead.assign_service_rm",
                                            { lead_name: doc.name, service_rm: rm.employee }
                                        ).then(() => {
                                            close()
                                            toast.success("Assigned to " + rm.employee_name)
                                            setTimeout(() => window.location.href = window.location.href, 1500)
                                        }).catch((e) => { close(); toast.error(e.message || "Error") })
                                    }
                                }))
                            })
                        }
                    }).catch(() => {
                        // Not a manager — check if RM already assigned
                        if (doc.custom_service_rm) {
                            toast.error("Service RM already assigned. Contact your manager to change.")
                            return
                        }
                        // Normal RM: show suggestion only
                        call("aionion_custom.aionion_custom.controllers.crm_lead.get_suggested_service_rm",
                            { lead_name: doc.name }
                        ).then((suggestion) => {
                            $dialog({
                                title: "Assign Service RM",
                                message: "Suggested: " + (suggestion.service_rm_name || "None") + " | " + (suggestion.reason || ""),
                                actions: [{
                                    label: "Confirm & Assign",
                                    variant: "solid",
                                    onClick: (close) => {
                                        if (!suggestion.service_rm) { toast.error("No Service RM available"); close(); return }
                                        call("aionion_custom.aionion_custom.controllers.crm_lead.assign_service_rm",
                                            { lead_name: doc.name, service_rm: suggestion.service_rm }
                                        ).then(() => {
                                            close()
                                            toast.success("Service RM assigned: " + suggestion.service_rm_name)
                                            setTimeout(() => window.location.href = window.location.href, 1500)
                                        }).catch((e) => { close(); toast.error(e.message || "Error") })
                                    }
                                }]
                            })
                        }).catch((e) => { toast.error(e.message || "Error") })
                    })
                }
            })
        }

        if ((!doc.docstatus || doc.docstatus === 0) && doc.custom_product !== "SME") {
            actions.push({
                label: "Submit Lead",
                onClick: () => {
                    if (!doc.custom_policy_status) { toast.error("Please set Policy Status before submitting."); return }
                    if (doc.custom_policy_status === "Issued" && !doc.custom_policy_number) { toast.error("Policy Number is mandatory when Policy Status is Issued."); return }
                    $dialog({
                        title: "Submit Lead",
                        message: "Are you sure? Lead will be locked after submission.",
                        actions: [{
                            label: "Submit",
                            variant: "solid",
                            onClick: (close) => {
                                call("aionion_custom.aionion_custom.controllers.crm_lead.submit_insurance_lead",
                                    { lead_name: doc.name }
                                ).then(() => {
                                    close()
                                    toast.success("Lead submitted! MIS team will now verify.")
                                    setTimeout(() => window.location.href = window.location.href, 1500)
                                }).catch((e) => { close(); toast.error(e.message || "Something went wrong") })
                            }
                        }]
                    })
                }
            })
        }

        if (doc.docstatus === 1 && doc.custom_product !== "Insurance Renewals") {
            if (doc.custom_mis_status !== "Approved") {
                actions.push({
                    label: "Verify MIS",
                    onClick: () => {
                        $dialog({
                            title: "Verify MIS",
                            message: "Have you verified Policy No " + (doc.custom_policy_number || "N/A") + " in the insurer portal?",
                            actions: [{
                                label: "Verify",
                                variant: "solid",
                                onClick: (close) => {
                                    call("aionion_custom.aionion_custom.controllers.crm_lead.approve_mis",
                                        { lead_name: doc.name }
                                    ).then(() => {
                                        close()
                                        toast.success("MIS Verified!")
                                        setTimeout(() => window.location.href = window.location.href, 1500)
                                    }).catch((e) => { close(); toast.error(e.message || "Error") })
                                }
                            }]
                        })
                    }
                })
            }

            if (doc.custom_mis_status !== "Rejected") {
                actions.push({
                    label: "Reject MIS",
                    onClick: () => {
                        $dialog({
                            title: "Reject MIS",
                            message: "Reject MIS for " + doc.lead_name + "? Lead will be unlocked.",
                            actions: [{
                                label: "Reject",
                                variant: "solid",
                                onClick: (close) => {
                                    call("aionion_custom.aionion_custom.controllers.crm_lead.reject_mis",
                                        { lead_name: doc.name }
                                    ).then(() => {
                                        close()
                                        toast.success("MIS Rejected. Lead unlocked.")
                                        setTimeout(() => window.location.href = window.location.href, 1500)
                                    }).catch((e) => { close(); toast.error(e.message || "Error") })
                                }
                            }]
                        })
                    }
                })
            }
        }
    }



    // ── AIONION CAPITAL ──────────────────────────────────────
    if (doc.custom_entity === "Aionion Capital") {
        const product = doc.custom_product
        const dtMap = {"Bonds":"bonds-purchase-record","Mutual Funds":"mutual-funds-record","Account Opening":"equity-record"}
        const labelMap = {"Bonds":"Bonds Details","Mutual Funds":"Mutual Funds Details","Account Opening":"Account Opening Details"}
        if (product && dtMap[product]) {
            actions.push({ label: labelMap[product], onClick: () => {
                call("aionion_custom.aionion_custom.controllers.crm_lead.get_or_create_capital_record",{lead_name:doc.name})
                .then((rec)=>{ window.location.href="/app/"+dtMap[product]+"/"+rec.name })
                .catch((e)=>{ toast.error(e.message||"Error") })
            }})
        }
        /* CAPITAL ASSIGN RM — uncomment to enable
        actions.push({
            label: "Assign Service RM",
            onClick: () => {
                call("aionion_custom.aionion_custom.controllers.crm_lead.get_rm_list_for_manager",{lead_name:doc.name})
                .then((res)=>{
                    if(res.is_manager){
                        $dialog({title:"Assign Capital RM",message:"Select RM:",actions:res.rm_list.map(rm=>({
                            label:rm.employee_name+" — "+rm.lead_count+" leads",variant:"outline",
                            onClick:(close)=>{
                                call("aionion_custom.aionion_custom.controllers.crm_lead.assign_service_rm",{lead_name:doc.name,service_rm:rm.employee})
                                .then(()=>{close();toast.success("Assigned to "+rm.employee_name);setTimeout(()=>window.location.href=window.location.href,1500)})
                                .catch((e)=>{close();toast.error(e.message||"Error")})
                            }
                        }))})
                    }
                }).catch(()=>{toast.error("Only Capital Managers can assign RM")})
            }
        })
        */
        if (!doc.docstatus||doc.docstatus===0) {
            actions.push({label:"Submit Capital Lead",onClick:()=>{
                $dialog({title:"Submit Capital Lead",message:"Submit for MIS verification?",actions:[{label:"Submit",variant:"solid",onClick:(close)=>{
                    call("aionion_custom.aionion_custom.controllers.crm_lead.submit_capital_lead",{lead_name:doc.name})
                    .then(()=>{close();toast.success("Submitted!");setTimeout(()=>window.location.href=window.location.href,1500)})
                    .catch((e)=>{close();toast.error(e.message||"Error")})
                }}]})
            }})
        }
        if (doc.docstatus===1) {
            if (doc.custom_mis_status!=="Approved") {
                actions.push({label:"Verify Capital MIS",onClick:()=>{
                    $dialog({title:"Verify Capital MIS",message:"Confirm transaction?",actions:[{label:"Verify",variant:"solid",onClick:(close)=>{
                        call("aionion_custom.aionion_custom.controllers.crm_lead.approve_capital_mis",{lead_name:doc.name})
                        .then(()=>{close();toast.success("Verified!");setTimeout(()=>window.location.href=window.location.href,1500)})
                        .catch((e)=>{close();toast.error(e.message||"Error")})
                    }}]})
                }})
            }
            if (doc.custom_mis_status!=="Rejected") {
                actions.push({label:"Reject Capital MIS",onClick:()=>{
                    $dialog({title:"Reject Capital MIS",message:"Reject? Lead will be unlocked.",actions:[{label:"Reject",variant:"solid",onClick:(close)=>{
                        call("aionion_custom.aionion_custom.controllers.crm_lead.reject_capital_mis",{lead_name:doc.name})
                        .then(()=>{close();toast.success("Rejected.");setTimeout(()=>window.location.href=window.location.href,1500)})
                        .catch((e)=>{close();toast.error(e.message||"Error")})
                    }}]})
                }})
            }
        }
    }
        // ── US SUBSCRIPTION ──────────────────────────────────────
    if (doc.custom_entity === "US Subscription") {

        if (doc.docstatus === 1) {
            call("aionion_custom.aionion_custom.controllers.crm_lead.get_product_data",
                { lead_name: doc.name, product: "US Subscription" }
            ).then((rec) => {
                if (!rec) return
                const payStatus = rec.payment_status || "Pending"
                toast[payStatus === "Approved" ? "success" : payStatus === "Rejected" ? "error" : "warning"](
                    `Payment: ${payStatus} | Amount: ${rec.amount_paid_us_subs > 0 ? rec.amount_paid_us_subs : "Not filled"} | Email: ${rec.email_address || rec.client_email || "—"} | Start: ${rec.sub_start_date || rec.sub_start_month || "—"} | End: ${rec.sub_end_date || rec.sub_end_month || "—"}`
                )
            })
        }

        if ((!doc.docstatus || doc.docstatus === 0) && !doc.custom_service_rm) {
            actions.push({
                label: "Assign Service RM",
                onClick: () => {
                    call("aionion_custom.aionion_custom.controllers.crm_lead.get_suggested_service_rm",
                        { lead_name: doc.name }
                    ).then((suggestion) => {
                        $dialog({
                            title: "Assign Service RM",
                            message: "Suggested: " + (suggestion.service_rm_name || "None") + " | " + (suggestion.reason || ""),
                            actions: [{
                                label: "Confirm & Assign",
                                variant: "solid",
                                onClick: (close) => {
                                    if (!suggestion.service_rm) { toast.error("No US Subscription RM available"); close(); return }
                                    call("aionion_custom.aionion_custom.controllers.crm_lead.assign_service_rm",
                                        { lead_name: doc.name, service_rm: suggestion.service_rm }
                                    ).then(() => {
                                        close()
                                        toast.success("Service RM assigned: " + suggestion.service_rm_name)
                                        setTimeout(() => window.location.href = window.location.href, 1500)
                                    }).catch((e) => { close(); toast.error(e.message || "Error assigning Service RM") })
                                }
                            }]
                        })
                    }).catch((e) => { toast.error(e.message || "Error getting suggestion") })
                }
            })
        }

        actions.push({
            label: "US Subscription Details",
            onClick: () => {
                call("aionion_custom.aionion_custom.controllers.crm_lead.get_product_data",
                    { lead_name: doc.name, product: "US Subscription" }
                ).then((record) => {
                    if (record && record.name) {
                        window.location.href = "/app/us-subscription-record/" + record.name
                    } else {
                        call("aionion_custom.aionion_custom.controllers.crm_lead.create_us_subscription_from_lead",
                            { lead_name: doc.name }
                        ).then((new_record) => {
                            window.location.href = "/app/us-subscription-record/" + new_record
                        }).catch((e) => { toast.error(e.message || "Error creating record") })
                    }
                })
            }
        })

        if (!doc.docstatus || doc.docstatus === 0) {
            actions.push({
                label: "Submit US Lead",
                onClick: () => {
                    const mandatory = {
                        "lead_name": "Client Name",
                        "mobile_no": "Contact Number",
                        "email": "Email",
                        "custom_country": "Country of Residence",
                        "custom_employee_status": "Employment Status",
                        "custom_client_indian_investments": "Indian Investments",
                        "custom_client_intended_investment_in_us_market": "Intended Investment",
                        "custom_aionion_client_code": "Aionion Client Code",
                    }
                    const missing = Object.entries(mandatory)
                        .filter(([field]) => !doc[field])
                        .map(([, label]) => label)
                    if (missing.length) { toast.error("Missing: " + missing.join(", ")); return }
                    $dialog({
                        title: "Submit US Lead",
                        message: "Submit this lead for payment verification by MIS?",
                        actions: [{
                            label: "Submit",
                            variant: "solid",
                            onClick: (close) => {
                                call("aionion_custom.aionion_custom.controllers.crm_lead.submit_us_lead",
                                    { lead_name: doc.name }
                                ).then(() => {
                                    close()
                                    toast.success("US Lead submitted! MIS team will verify payment.")
                                    setTimeout(() => window.location.href = window.location.href, 1500)
                                }).catch((e) => { close(); toast.error(e.message || "Something went wrong") })
                            }
                        }]
                    })
                }
            })
        }

        if (doc.docstatus === 1) {
            if (doc.custom_mis_status !== "Approved") {
                actions.push({
                    label: "Verify Payment",
                    onClick: () => {
                        $dialog({
                            title: "Verify Payment",
                            message: "Confirm payment received for " + doc.lead_name + "?",
                            actions: [{
                                label: "Verify",
                                variant: "solid",
                                onClick: (close) => {
                                    call("aionion_custom.aionion_custom.controllers.crm_lead.verify_us_payment",
                                        { lead_name: doc.name }
                                    ).then(() => {
                                        close()
                                        toast.success("Payment verified!")
                                        setTimeout(() => window.location.href = window.location.href, 1500)
                                    }).catch((e) => { close(); toast.error(e.message || "Error") })
                                }
                            }]
                        })
                    }
                })
            }

            if (doc.custom_mis_status !== "Rejected") {
                actions.push({
                    label: "Reject Payment",
                    onClick: () => {
                        $dialog({
                            title: "Reject Payment",
                            message: "Reason for rejection?",
                            actions: [{
                                label: "Reject",
                                variant: "solid",
                                onClick: (close) => {
                                    call("aionion_custom.aionion_custom.controllers.crm_lead.reject_us_payment",
                                        { lead_name: doc.name }
                                    ).then(() => {
                                        close()
                                        toast.error("Payment rejected.")
                                        setTimeout(() => window.location.href = window.location.href, 1500)
                                    }).catch((e) => { close(); toast.error(e.message || "Error") })
                                }
                            }]
                        })
                    }
                })
            }
        }
    }


    // ── SME INSURANCE ────────────────────────────────────────
    if (doc.custom_entity === "Aionion Insurance" && doc.custom_product === "SME") {

        actions.push({
            label: "SME Insurance Record",
            onClick: () => {
                call("aionion_custom.aionion_custom.controllers.crm_lead.get_or_create_sme_record",
                    { lead_name: doc.name }
                ).then((rec) => {
                    window.location.href = "/app/sme-insurance-record/" + rec.name
                }).catch((e) => { toast.error(e.message || "Error opening SME record") })
            }
        })

        if (!doc.docstatus || doc.docstatus === 0) {
            actions.push({
                label: "Submit SME Lead",
                onClick: () => {
                    $dialog({
                        title: "Submit SME Lead",
                        message: "Submit this lead for MIS verification?",
                        actions: [{
                            label: "Submit",
                            variant: "solid",
                            onClick: (close) => {
                                call("aionion_custom.aionion_custom.controllers.crm_lead.submit_sme_lead",
                                    { lead_name: doc.name }
                                ).then(() => {
                                    close()
                                    toast.success("SME Lead submitted!")
                                    setTimeout(() => window.location.href = window.location.href, 1500)
                                }).catch((e) => { close(); toast.error(e.message || "Something went wrong") })
                            }
                        }]
                    })
                }
            })
        }

        if (doc.docstatus === 1) {
            if (doc.custom_mis_status !== "Approved") {
                actions.push({
                    label: "Verify SME MIS",
                    onClick: () => {
                        $dialog({
                            title: "Verify SME MIS",
                            message: "Confirm policy verified for " + doc.lead_name + "?",
                            actions: [{
                                label: "Verify",
                                variant: "solid",
                                onClick: (close) => {
                                    call("aionion_custom.aionion_custom.controllers.crm_lead.approve_sme_mis",
                                        { lead_name: doc.name }
                                    ).then(() => {
                                        close()
                                        toast.success("SME MIS Verified!")
                                        setTimeout(() => window.location.href = window.location.href, 1500)
                                    }).catch((e) => { close(); toast.error(e.message || "Error") })
                                }
                            }]
                        })
                    }
                })
            }
            if (doc.custom_mis_status !== "Rejected") {
                actions.push({
                    label: "Reject SME MIS",
                    onClick: () => {
                        $dialog({
                            title: "Reject SME MIS",
                            message: "Reject MIS for " + doc.lead_name + "? Lead will be unlocked.",
                            actions: [{
                                label: "Reject",
                                variant: "solid",
                                onClick: (close) => {
                                    call("aionion_custom.aionion_custom.controllers.crm_lead.reject_sme_mis",
                                        { lead_name: doc.name }
                                    ).then(() => {
                                        close()
                                        toast.error("SME MIS Rejected.")
                                        setTimeout(() => window.location.href = window.location.href, 1500)
                                    }).catch((e) => { close(); toast.error(e.message || "Error") })
                                }
                            }]
                        })
                    }
                })
            }
        }
    }

    return { actions }
}
